SELECT ?country WHERE {
  ?book wdt:P31 wd:Q718300 ;
         wdt:P1476 "One Hundred Years of Solitude"@en.
  ?book wdt:P50 ?author.
  ?author wdt:P27 ?country.
}

SELECT ?country WHERE {
  ?book wdt:P31 wd:Q718300;
         wdt:P1476 "Cien años de soledad"@es;
         wdt:P50 ?author.
  ?author wdt:P27 ?country.
}

SELECT ?countryLabel WHERE {
  wd:Q825 wdt:P27 ?country.
  ?country rdfs:label ?countryLabel.
  FILTER (lang(?countryLabel) = "en")
}

